import asyncio
from dataclasses import dataclass, field
from typing import Callable, Awaitable, Optional
from enum import Enum

class ProviderStatus(str, Enum):
    HEALTHY = "healthy"
    DEGRADED = "degraded"
    DOWN = "down"

@dataclass
class ProviderConfig:
    name: str
    model: str
    priority: int            # lower = preferred
    rate_limit_rpm: int
    region: str              # for data residency tracking
    status: ProviderStatus = ProviderStatus.HEALTHY
    failure_count: int = field(default=0, repr=False)
    _last_failure: Optional[float] = field(default=None, repr=False)

@dataclass
class FailoverRouter:
    providers: list[ProviderConfig]

    def available_providers(self) -> list[ProviderConfig]:
        return sorted(
            [p for p in self.providers if p.status != ProviderStatus.DOWN],
            key=lambda p: p.priority,
        )

    async def route(
        self,
        call_fn: Callable[[ProviderConfig], Awaitable[str]],
        fallback: Optional[Callable[[], str]] = None,
    ) -> str:
        for provider in self.available_providers():
            try:
                result = await asyncio.wait_for(
                    call_fn(provider),
                    timeout=provider.rate_limit_rpm / 60,  # crude timeout
                )
                provider.failure_count = 0
                return result
            except asyncio.TimeoutError:
                provider.failure_count += 1
                if provider.failure_count >= 3:
                    provider.status = ProviderStatus.DOWN
            except Exception:
                provider.failure_count += 1

        if fallback:
            return fallback()
        raise RuntimeError("All providers failed and no fallback configured")

# FNOL chatbot — dual-provider with Azure primary, OpenAI fallback
router = FailoverRouter(providers=[
    ProviderConfig(
        name="azure-west-europe",
        model="gpt-4o-2024-11-20",
        priority=1,
        rate_limit_rpm=3500,
        region="EU-West",
    ),
    ProviderConfig(
        name="openai-direct",
        model="gpt-4o-2024-11-20",
        priority=2,
        rate_limit_rpm=1000,
        region="US",          # WARNING: data residency implication — see ADR-001
    ),
])
